import React from "react";
import { useQuery } from "@tanstack/react-query";
import "../HomePage/home.scss";
import { fetchMovie } from "../../utils/fetchApi";
import { Link } from "react-router-dom";
const Home = () => {
  const Img_URL = "https://image.tmdb.org/t/p/original/";

  const {
    isError,
    isLoading,
    error,
    data: upcoming,
  } = useQuery({
    queryKey: ["Movie", "Upcoming"],
    queryFn: () =>
      fetchMovie("upcoming").then((res) => {
        return res.results;
      }),
  });

  const { data: Toprated } = useQuery({
    queryKey: ["Movie", "Toprated"],
    queryFn: () =>
      fetchMovie("top_rated").then((res) => {
        return res.results;
      }),
  });

  const { data: Popular } = useQuery({
    queryKey: ["Movie", "Popular"],
    queryFn: () =>
      fetchMovie("popular").then((res) => {
        return res.results;
      }),
  });

  let Row;
  if (isLoading) {
    return (
      <div className="loading">
        <h1>Loading</h1>
      </div>
    );
  } else if (isError) {
    return (
      <div className="error">
        <p>{error.message}</p>
      </div>
    );
  } else {
    Row = ({ title, arr = [] }) => {
      return (
        <div className="row">
          <h1>{title}</h1>
          <div>
          {arr.map((item) => (
            <div className="card" key={item.title}>
              <Link to={"/"}>
                <img src={`${Img_URL}${item.poster_path}`} alt="img" />
              </Link>
            </div>
          ))}
          </div>
        </div>
      );
    };
  }
  return (
    <section className="home">
      <div
        className="banner"
        style={{
          backgroundImage: Popular
            ? `url(${`${Img_URL}${Popular[0].backdrop_path}`})`
            : "rgb(0,0,0)",
        }}
      >
      </div>
        <Row title={"Popular"} arr={Popular} />
    </section>
  );
};

export default Home;
